function signIn(prompt_mode) {
  prompt_mode = prompt_mode || 'select_account';
  location.href = 'https://accounts.google.com/o/oauth2/v2/auth'
    + '?client_id=' + encodeURIComponent(CLIENT_ID)
    + '&redirect_uri=' + encodeURIComponent(REDIRECT_URI)
    + '&response_type=token&scope=' + encodeURIComponent(SCOPES)
    + '&prompt=' + prompt_mode;
}
function saveToken(t) {
  var expiry = (Date.now() + 55*60*1000).toString();
  sessionStorage.setItem('lfiag_token', t);
  sessionStorage.setItem('lfiag_expiry', expiry);
  // localStorage pour la persistance PWA iOS (sessionStorage vidé à la fermeture)
  try {
    localStorage.setItem('lfiag_token', t);
    localStorage.setItem('lfiag_expiry', expiry);
  } catch(e) {}
}
function getToken() {
  // Lire depuis sessionStorage en priorité, sinon localStorage (PWA iOS)
  var t = sessionStorage.getItem('lfiag_token') || localStorage.getItem('lfiag_token');
  var e = +(sessionStorage.getItem('lfiag_expiry') || localStorage.getItem('lfiag_expiry')) || 0;
  if (!t || Date.now() > e) {
    sessionStorage.removeItem('lfiag_token');
    sessionStorage.removeItem('lfiag_expiry');
    try { localStorage.removeItem('lfiag_token'); localStorage.removeItem('lfiag_expiry'); } catch(e2) {}
    return null;
  }
  // Synchroniser sessionStorage si token vient du localStorage
  if (!sessionStorage.getItem('lfiag_token') && t) {
    sessionStorage.setItem('lfiag_token', t);
    sessionStorage.setItem('lfiag_expiry', e.toString());
  }
  return t;
}
function scheduleTokenRefresh() {
  var delay=(+sessionStorage.getItem('lfiag_expiry')||0)-Date.now()-120000;
  if(delay<=0)return;
  setTimeout(function(){toast('Session expire bientôt…');setTimeout(function(){signIn('none');},2000);},delay);
}

// ── iOS fake-fullscreen (position:fixed) ────────────────────
var _isIOS = /iPhone|iPad|iPod/.test(navigator.userAgent) && !window.MSStream;
var _iosFakeFS = false;

function _iosEnterFakeFS() {
  if (_iosFakeFS) return;
  _iosFakeFS = true;
  var bd = document.querySelector('.modal-backdrop');
  if (bd) bd.classList.add('ios-fake-fs');
  document.body.classList.add('ios-fake-fs-active');
  try { if (screen.orientation && screen.orientation.lock) screen.orientation.lock('landscape').catch(function(){}); } catch(e) {}
}

function _iosExitFakeFS() {
  if (!_iosFakeFS) return;
  _iosFakeFS = false;
  var bd = document.querySelector('.modal-backdrop');
  if (bd) bd.classList.remove('ios-fake-fs');
  document.body.classList.remove('ios-fake-fs-active');
  try { if (screen.orientation && screen.orientation.unlock) screen.orientation.unlock(); } catch(e) {}
}

// Auto fake-fs au passage en paysage iOS
window.addEventListener('orientationchange', function() {
  if (!_isIOS) return;
  var modal = document.getElementById('modal');
  if (!modal || !modal.classList.contains('open')) return;
  setTimeout(function() {
    var land = window.innerWidth > window.innerHeight;
    if (land && !_iosFakeFS) _iosEnterFakeFS();
    else if (!land && _iosFakeFS) _iosExitFakeFS();
  }, 150);
});

// ── Alune preview ───────────────────────────────────────────
var _aluneHoverTimer = null;

function aluneStartPreview(card) {
  // Ne jamais jouer si le modal est ouvert
  if (document.getElementById('modal').classList.contains('open')) return;
  var img = card.querySelector('.alune-thumb--img');
  var vid = card.querySelector('.alune-thumb--video');
  var bar = card.querySelector('.alune-preview-bar');
  if (!vid || vid._playing) return;
  vid._playing = true;
  card.classList.add('alune-card--playing');
  img.style.opacity = '0';
  vid.muted = false; vid.volume = 0; vid.currentTime = 0;
  vid.play().catch(function() { vid.muted = true; vid.volume = 1; vid.play(); });
  vid.classList.add('is-visible');
  if (vid._volIv) clearInterval(vid._volIv);
  vid._volIv = setInterval(function() {
    if (!vid.muted) vid.volume = Math.min(1, vid.volume + 0.05);
    if (vid.volume >= 1) { clearInterval(vid._volIv); vid._volIv = null; }
  }, 75);
  if (vid._barIv) clearInterval(vid._barIv);
  if (bar) vid._barIv = setInterval(function() {
    if (vid.duration) bar.style.width = (vid.currentTime / vid.duration * 100) + '%';
  }, 200);
  if (vid._endFn) vid.removeEventListener('ended', vid._endFn);
  vid._endFn = function() { aluneStopPreview(card); };
  vid.addEventListener('ended', vid._endFn);
}

function aluneStopPreview(card) {
  var img = card.querySelector('.alune-thumb--img');
  var vid = card.querySelector('.alune-thumb--video');
  var bar = card.querySelector('.alune-preview-bar');
  if (!vid || !vid._playing) return;
  vid._playing = false;
  card.classList.remove('alune-card--playing');
  if (vid._volIv) { clearInterval(vid._volIv); vid._volIv = null; }
  if (vid._barIv) { clearInterval(vid._barIv); vid._barIv = null; }
  if (vid._endFn) { vid.removeEventListener('ended', vid._endFn); vid._endFn = null; }
  vid.pause(); vid.currentTime = 0;
  vid.classList.remove('is-visible');
  if (bar) bar.style.width = '0%';
  img.style.opacity = '1';
}

function aluneMuteToggle(btn) {
  var vid = btn.closest('.alune-card').querySelector('.alune-thumb--video');
  if (!vid) return;
  vid.muted = !vid.muted;
  var icon = btn.querySelector('.alune-mute-icon');
  if (icon) icon.innerHTML = vid.muted
    ? '<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>'
    : '<polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"/>';
}

(function() {
  if (!('IntersectionObserver' in window)) return;

  // Carte la plus centrée dans le viewport gagne
  var _visibleCards = new Map(); // card → intersectionRatio
  var _scrolled = false;
  window.addEventListener('scroll', function() { _scrolled = true; }, {once:true, passive:true});

  function _pickBest() {
    if (!_scrolled || _visibleCards.size === 0) return null;
    var vpMid = window.innerHeight / 2;
    var best = null, bestScore = -1;
    _visibleCards.forEach(function(ratio, card) {
      if (ratio < 0.70) return;
      var rect = card.getBoundingClientRect();
      var cardMid = rect.top + rect.height / 2;
      var score = ratio - Math.abs(cardMid - vpMid) / window.innerHeight;
      if (score > bestScore) { bestScore = score; best = card; }
    });
    return best;
  }

  // Cache list of alune cards (avoid O(n) DOM query each update)
  var _aluneCards = [];
  function _refreshAluneCards(){ _aluneCards = Array.prototype.slice.call(document.querySelectorAll('.alune-card--preview')); }
  function _updatePlaying() {
    // Skip entirely on low-end devices (video previews hidden by CSS)
    if (document.documentElement.classList.contains('low-end')) return;
    var best = _pickBest();
    if (!_aluneCards.length) _refreshAluneCards();
    for (var i = 0; i < _aluneCards.length; i++) {
      var card = _aluneCards[i];
      var vid = card.querySelector('.alune-thumb--video');
      if (!vid) continue;
      if (card === best) {
        if (!vid._playing && !card._ioTimer) {
          (function(c){
            c._ioTimer = setTimeout(function() {
              c._ioTimer = null;
              for (var j = 0; j < _aluneCards.length; j++) {
                if (_aluneCards[j] !== c) aluneStopPreview(_aluneCards[j]);
              }
              aluneStartPreview(c);
            }, 800);
          })(card);
        }
      } else {
        if (card._ioTimer) { clearTimeout(card._ioTimer); card._ioTimer = null; }
        if (vid._playing) aluneStopPreview(card);
      }
    }
  }

  var obs = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      var _thresh = parseFloat(entry.target.dataset.previewThresh || '0.70');
      if (entry.intersectionRatio >= _thresh) {
        _visibleCards.set(entry.target, entry.intersectionRatio);
      } else {
        _visibleCards.delete(entry.target);
        if (entry.target._ioTimer) { clearTimeout(entry.target._ioTimer); entry.target._ioTimer = null; }
        aluneStopPreview(entry.target);
      }
    });
    _updatePlaying();
  }, {threshold:[0,0.40,0.70,1.0]});

  function bindAluneCard(card) {
    if (!card.querySelector('.alune-thumb--video')) return;
    obs.observe(card);
    if (!isMobile()) {
      card.addEventListener('mouseenter', function() {
        // Desktop : arrêter les autres avant de lancer
        if (_aluneHoverTimer) clearTimeout(_aluneHoverTimer);
        _aluneHoverTimer = setTimeout(function() {
          document.querySelectorAll('.alune-card--preview').forEach(function(c) {
            if (c !== card) aluneStopPreview(c);
          });
          aluneStartPreview(card);
        }, 800);
      });
      card.addEventListener('mouseleave', function() {
        if (_aluneHoverTimer) { clearTimeout(_aluneHoverTimer); _aluneHoverTimer = null; }
        aluneStopPreview(card);
      });
    }
    var _lt;
    card.addEventListener('touchstart', function() { _lt = setTimeout(function() { aluneStartPreview(card); }, 500); }, {passive:true});
    card.addEventListener('touchend', function() { clearTimeout(_lt); }, {passive:true});
    card.addEventListener('touchmove', function() { clearTimeout(_lt); }, {passive:true});
  }

  function init() { document.querySelectorAll('.alune-card--preview').forEach(bindAluneCard); _refreshAluneCards(); }
  document.addEventListener('lfiag:ready', init);
  if (document.readyState !== 'loading') setTimeout(init, 500);
})();


// ── Pastilles NEW ────────────────────────────────────────────
var NEW_TTL = 7 * 24 * 3600 * 1000; // 7 jours

function _catSeenKey(cat) {
  return 'lfiag_seen_' + (currentUser && currentUser.email ? currentUser.email + '_' : '') + cat;
}

function _catHasNew(cat) {
  var seenTs;
  try { seenTs = parseInt(localStorage.getItem(_catSeenKey(cat)) || '0'); } catch(e) { seenTs = 0; }
  var now = Date.now();
  return allVideos.some(function(v) {
    if (v._cat !== cat) return false;
    var mt = v.modifiedTime ? new Date(v.modifiedTime).getTime() : 0;
    return mt > seenTs && (now - mt) < NEW_TTL;
  });
}

function _markCatSeen(cat) {
  try { localStorage.setItem(_catSeenKey(cat), Date.now().toString()); } catch(e) {}
}

function _updateAluneNew() {
  // Vignettes À la une : The Voice 2026 et L'Effet Lara
  var aluneMap = {
    'The Voice 2026': 'The Voice 2026',
    "L'Effet Lara - 2026": "L'Effet Lara - 2026"
  };
  document.querySelectorAll('.alune-card[data-cat]').forEach(function(card) {
    var cat = card.dataset.cat;
    if (!cat) return;
    var existing = card.querySelector('.alune-badge-new');
    if (_catHasNew(cat)) {
      if (!existing) {
        var b = document.createElement('div');
        b.className = 'alune-badge-new';
        b.textContent = 'NEW';
        card.appendChild(b);
      }
    } else {
      if (existing) existing.remove();
    }
  });
}

