async function handleCallback() {
  const hash = location.hash;
  let accessToken = getToken();

  if (hash.includes('access_token=')) {
    const params = new URLSearchParams(hash.slice(1));
    accessToken = params.get('access_token');
    saveToken(accessToken);
    history.replaceState({}, document.title, location.pathname);
  }

  if (!accessToken) { showScreen('auth'); return; }

  showScreen('loading');
  setLoadingMsg('Connexion…');
  // Timeout de sécurité : forcer la fermeture du loader après 18s
  window._loaderSafetyTimer = setTimeout(function() {
    _hideLoader();
    var content = document.getElementById('content');
    if (content && !content.innerHTML.trim()) {
      content.innerHTML = '<div class="empty-state"><h3>Chargement lent</h3>'
        + '<p>Le serveur met du temps à répondre.</p>'
        + '<button class="btn" onclick="handleCallback()" style="margin:1rem auto">&#8635; Réessayer</button></div>';
    }
  }, 18000);

  try {
    // ── Étape 1 : profil utilisateur (~0s depuis cache, ~0.2s depuis Google) ──
    var cachedUser = null;
    try { cachedUser = JSON.parse(sessionStorage.getItem('lfiag_user') ||
                                  localStorage.getItem('lfiag_user') || 'null'); } catch(e) {}

    if (cachedUser && cachedUser.email) {
      currentUser = Object.assign({}, cachedUser, { token: accessToken });
    } else {
      const res = await fetch('https://www.googleapis.com/oauth2/v3/userinfo',
        { headers: { Authorization: 'Bearer ' + accessToken } });
      if (!res.ok) throw new Error('Token invalide');
      const info = await res.json();
      currentUser = { email: info.email, name: info.name || info.email, token: accessToken };
      try {
        var u = JSON.stringify(currentUser);
        sessionStorage.setItem('lfiag_user', u);
        localStorage.setItem('lfiag_user', u);
      } catch(e) {}
    }

    // ── Étape 2 : cache accès (TTL=0 — re-checker à chaque ouverture) ─
    var cachedAccess = null;
    try {
      var ca = JSON.parse(localStorage.getItem('lfiag_access') || 'null');
      if (ca && ca.email === currentUser.email && ca.ts && (Date.now() - ca.ts) < 0) // TTL=0
        cachedAccess = ca;
    } catch(e) {}

    // Rôle par défaut en attendant la confirmation du check
    currentUser.role = (cachedAccess && cachedAccess.role) || 'user';

    // ── Étape 3 : laisser le loader s'initialiser (1 tick) ──────
    // puis charger les vidéos et vérifier l'accès
    await new Promise(function(r){ setTimeout(r, 100); });
    showAppUI();
    _loadVideosAndShow();

    // ── Étape 4 : check accès en ARRIÈRE-PLAN (jamais bloquant) ──
    _checkAccessBackground();

  } catch(e) {
    sessionStorage.removeItem('lfiag_token');
    try { localStorage.removeItem('lfiag_user');
          localStorage.removeItem('lfiag_access'); } catch(ex) {}
    showScreen('auth');
    toast('Erreur de connexion : ' + e.message);
  }
}

// Charger et afficher les vidéos — jamais bloquant
async function _loadVideosAndShow() {
  try {
    var cached = null, cacheAge = Infinity;
    try {
      var raw = localStorage.getItem('lfiag_videos_cache');
      if (raw) { var p = JSON.parse(raw);
        if (p && p.videos && p.videos.length > 0) {
          cached = p.videos; cacheAge = Date.now() - (p.ts || 0); } }
    } catch(e) {}

    if (cached && cached.length > 0) {
      // Cache local disponible : afficher instantanément
      allVideos = dedup(cached).map(function(v){
        return Object.assign({},v,{_cat:categorize(v)}); });
      renderAll(); // appelle showScreen('app')
      // Rafraîchir en arrière-plan si cache > 5min
      if (cacheAge > 300000) {
        // Attendre la fin du loader avant de rafraîchir (évite double animation barre)
        var loaderDelay = window._loaderStart ? Math.max(500, 5300 - (Date.now() - window._loaderStart)) : 500;
        setTimeout(refreshVideosBackground, loaderDelay);
      }
    } else {
      // Pas de cache (1ère connexion / vide-cache) :
      // Garder le loader visible pendant tout le fetch — l'effet waouh doit durer
      setLoadingMsg('Chargement de la bibliothèque…');
      try {
        await fetchAndCacheVideos(true, false);
        // renderAll() dans fetchAndCacheVideos ferme le loader avec durée minimale 4.5s
      } catch(e) {
        _hideLoader();
        showScreen('app');
        document.getElementById('content').innerHTML =
          '<div class="empty-state"><h3>Connexion lente</h3><p>Le serveur met du temps à répondre.</p>' +
          '<button class="btn" onclick="_loadVideosAndShow()" style="margin:1rem auto">蘵 Réessayer</button></div>';
      }
    }
  } catch(e) { console.warn('loadVideos:', e); }
}
function _checkAccessBackground() {
  return callScript('check', { email: currentUser.email })
    .then(function(access) {
      access.ts = Date.now();
      access.email = currentUser.email;
      try { localStorage.setItem('lfiag_access', JSON.stringify(access)); } catch(e) {}
      // Accepter authorized:true (v9.1) OU status:'ok' (v9.3)
      var isOk = access.authorized === true || access.status === 'ok';
      if (!isOk) {
        signOut();
        toast('⚠ Accès non autorisé');
        return;
      }
      currentUser.role = access.role || 'member';
      // Rafraîchir le bouton admin si nécessaire
      var adminBtn = document.getElementById('adminHeaderBtn');
      if (adminBtn) adminBtn.style.display = currentUser.role === 'admin' ? 'flex' : 'none';
    })
    .catch(function() {
      // Silencieux si réseau indisponible — le cache reste valide
    });
}
// ============================================
// APPS SCRIPT
// ============================================
function callScript(action, params, retry) {
  params=params||{}; retry=retry||0;
  return new Promise(function(resolve,reject){
    var cb='cb_'+Math.random().toString(36).slice(2), done=false;
    var slowTimer=setTimeout(function(){
      if(!done) setLoadingMsg('Connexion lente… encore quelques secondes');
    },5000);
    var timer=setTimeout(function(){
      if(done)return; done=true; clearTimeout(slowTimer); delete window[cb];
      var el=document.getElementById(cb); if(el)el.remove();
      if(retry<1) callScript(action,params,retry+1).then(resolve).catch(reject);
      else reject(new Error('Serveur introuvable. Réessayez.'));
    },12000);
    window[cb]=function(data){
      if(done)return; done=true; clearTimeout(timer); clearTimeout(slowTimer); delete window[cb];
      var el=document.getElementById(cb); if(el)el.remove();
      if(data.status==='error') reject(new Error(data.message)); else resolve(data);
    };
    var s=document.createElement('script');
    s.id=cb;
    s.src=SCRIPT_URL+'?'+new URLSearchParams(Object.assign({action:action,callback:cb},params)).toString();
    s.onerror=function(){if(done)return;done=true;clearTimeout(timer);delete window[cb];reject(new Error('Erreur réseau'));};
    document.body.appendChild(s);
  });
}

// ============================================
// LOAD VIDEOS
// ============================================
async function loadVideos() {
  // Alias pour compatibilité — délègue à _loadVideosAndShow
  return _loadVideosAndShow();
}
function dedup(arr) {
  var s = {};
  return (arr||[]).filter(function(v){ if(!v||!v.id||s[v.id]) return false; s[v.id]=true; return true; });
}



async function refreshVideosBackground() {
  // Ne pas tourner si un refresh manuel est en cours
  if (window._refreshInProgress) return;
  try {
    // Pas de ts : le serveur sert son cache (rapide). Invalidation via bouton Actualiser.
    var data = await callScript('videos', { email: currentUser.email });
    var fresh = dedup(data.videos || []);
    try { localStorage.setItem('lfiag_videos_cache', JSON.stringify({videos: fresh, ts: Date.now()})); } catch(e) {}
    // Comparer IDs ET catégories pour détecter les renommages de dossiers
    var a = fresh.map(function(v){return v.id+'|'+(v._category||'');}).sort().join(',');
    var b = allVideos.map(function(v){return v.id+'|'+(v._cat||'');}).sort().join(',');
    if (a !== b) {
      allVideos = dedup(fresh).map(function(v){ return Object.assign({},v,{_cat:categorize(v)}); });
      renderAll();
    }
  } catch(e) { console.warn('bg refresh:', e.message); }
}

async function fetchAndCacheVideos(showErr, bustCache) {
  try {
    var params = { email: currentUser.email };
    if (bustCache) params.ts = Date.now();
    var data = await callScript('videos', params);
    var videos = dedup(data.videos || []);
    try { localStorage.setItem('lfiag_videos_cache', JSON.stringify({videos: videos, ts: Date.now()})); } catch(e) {}
    allVideos = videos.map(function(v){ return Object.assign({},v,{_cat:categorize(v)}); });
    renderAll();
  } catch(e) {
    if (showErr) document.getElementById('content').innerHTML =
      '<div class="empty-state"><h3>Chargement lent</h3><p>' + escHtml(e.message) + '</p>' +
      '<br><button class="btn btn-ghost" onclick="fetchAndCacheVideos(true)" style="margin:0 auto;">&#8635; Réessayer</button></div>';
  }
}


