function showScreen(name) {
  document.querySelectorAll('.screen').forEach(function(s){s.classList.remove('active','visible');});
  var el=document.getElementById('screen-'+name);
  el.classList.add('active');
  requestAnimationFrame(function(){el.classList.add('visible');});
  // Header
  var hdr = document.querySelector('header');
  if (hdr) hdr.style.display = (name === 'auth' || name === 'loading') ? 'none' : '';
  if (name === 'auth' || name === 'loading') {
    // Masquer explicitement tous les éléments header (styles inline résiduels)
    ['searchWrap','headerCatBtn','settingsBtn','refreshBtn','userBadge',
     'signOutBtn','adminHeaderBtn'].forEach(function(id) {
      var e = document.getElementById(id);
      if (e) e.style.display = 'none';
    });
  }
  if (name === 'auth') _preWarmAppsScript();
  if (name === 'app') _showHeaderElements();
  // Masquer le loader sur auth ou denied
  if (name === 'auth' || name === 'denied') {
    var loader = document.getElementById('lfiagLoader');
    if (loader && !loader._hiding) {
      loader._hiding = true;
      loader.classList.add('lfiag-hide');
      setTimeout(function() { if (loader.parentNode) loader.parentNode.removeChild(loader); }, 750);
    }
  }
}

function _initLfiagLoader() {
  if (window._loaderStart) return; // déjà initialisé
  window._loaderStart = Date.now();
  // Logo
  var img = document.getElementById('lfiagLoaderImg');
  if (img && LOGO_SRC) img.src = LOGO_SRC;
  // Particules canvas
  var canvas = document.getElementById('lfiagParticles');
  if (!canvas || canvas._lfiagInit) return;
  canvas._lfiagInit = true;
  var ctx = canvas.getContext('2d');
  function resize() { canvas.width = innerWidth; canvas.height = innerHeight; }
  resize();
  window.addEventListener('resize', resize);
  var pts = Array.from({length:45}, function() { return {
    x:Math.random()*innerWidth, y:Math.random()*innerHeight,
    r:Math.random()*1.3+0.3,
    vx:(Math.random()-.5)*.28, vy:(Math.random()-.5)*.28,
    a:Math.random()*.45+.1
  }; });
  (function draw() {
    if (!document.getElementById('lfiagParticles')) return;
    ctx.clearRect(0,0,canvas.width,canvas.height);
    pts.forEach(function(p) {
      p.x=(p.x+p.vx+canvas.width)%canvas.width;
      p.y=(p.y+p.vy+canvas.height)%canvas.height;
      ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle='rgba(120,180,255,'+p.a+')'; ctx.fill();
    });
    requestAnimationFrame(draw);
  })();
}
function _preWarmAppsScript() {
  try {
    if (window.__pw_done) return;
    window.__pw_done = true;
    var cb = '__pw_' + Date.now();
    window[cb] = function() { delete window[cb]; };
    var s = document.createElement('script');
    s.src = SCRIPT_URL + '?action=check&email=warmup&callback=' + cb;
    s.onload = function() { s.remove(); };
    s.onerror = function() { s.remove(); delete window[cb]; };
    document.head.appendChild(s);
    setTimeout(function() { delete window[cb]; }, 10000);
  } catch(e) {}
}

