// ============================================
// CATEGORIZE & RENDER
// ============================================
function categorize(video) {
  // Priorité à la catégorie renvoyée par le serveur (basée sur le dossier Drive)
  if (video._category) return video._category;
  // Fallback sur les règles locales par mots-clés
  const n = (video.name || '').toLowerCase();
  for (const r of settings.rules) { if (n.includes(r.keyword.toLowerCase())) return r.cat; }
  return 'Divers';
}



function normCat(s){ return _normCatKey(s); }
function _normCatKey(s) {
  var r = String(s).toLowerCase();
  r = r.replace(/[àâ]/g,'a').replace(/[éèê]/g,'e');
  r = r.replace(/[î]/g,'i').replace(/[ô]/g,'o').replace(/[ûù]/g,'u');
  r = r.replace(/['‘’‛]/g,'');
  r = r.replace(/[-\s]+/g,' ').trim();
  return r;
}
// Index normalisé de CAT_IMAGES (construit une seule fois)
var _CAT_IMAGES_IDX = null;
function _buildCatIndex() {
  if (_CAT_IMAGES_IDX) return;
  _CAT_IMAGES_IDX = {};
  Object.keys(CAT_IMAGES).forEach(function(k) {
    _CAT_IMAGES_IDX[_normCatKey(k)] = CAT_IMAGES[k];
  });
}
function getCatImage(cat) {
  _buildCatIndex();
  return CAT_IMAGES[cat] || _CAT_IMAGES_IDX[_normCatKey(cat)] || '';
}

function renderCatGrid() {
  var sec = document.getElementById('catGridSection');
  if (!sec) return;
  var cats = [...new Set(allVideos.map(function(v){return v._cat;}))].sort();
  if (!cats.length) { sec.style.display='none'; return; }
  if (activeCategory !== 'Tout' || searchQuery) { sec.style.display='none'; return; }
  sec.style.display = '';
  var grid = document.getElementById('catGrid');
  if (!grid) return;

  // Build coverflow 3D: transforme .cat-grid → .cov-stage (track + cards)
  grid.className = 'cov-stage';
  grid.innerHTML =
    '<div class="cov-bg" aria-hidden="true"></div>' +
    '<button class="cov-arrow cov-prev" aria-label="Précédent"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg></button>' +
    '<div class="cov-viewport"><div class="cov-track">' +
      cats.map(function(cat){
        var img = getCatImage(cat);
        return '<div class="cov-card" data-cat="'+escAttr(cat)+'" title="'+escAttr(cat)+'">'
          + (img ? '<picture><source type="image/webp" srcset="'+img.replace(/\.jpg$/,'.webp')+'"><img class="cov-img" src="'+img+'" alt="'+escAttr(cat)+'" loading="lazy"></picture>' : '<div class="cov-img" style="background:rgba(255,255,255,.06)"></div>')
          + '<div class="cov-overlay"></div>'
          + '<div class="cov-name">'+escHtml(cat)+'</div>'
          + (_catHasNew(cat) ? '<div class="badge-new">NEW</div>' : '')
          + '</div>';
      }).join('')
    + '</div></div>' +
    '<button class="cov-arrow cov-next" aria-label="Suivant"><svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="9 18 15 12 9 6"/></svg></button>' +
    '<div class="cov-dots"></div>';

  initCoverflow(grid, cats);
}

function initCoverflow(root, cats){
  var track = root.querySelector('.cov-track');
  var cards = Array.from(root.querySelectorAll('.cov-card'));
  var prev = root.querySelector('.cov-prev');
  var next = root.querySelector('.cov-next');
  var dots = root.querySelector('.cov-dots');
  var bg = root.querySelector('.cov-bg');
  var active = Math.floor(cats.length/2);
  var touchStartX = 0, touchStartY = 0, touching = false;
  var reducedMotion = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  // Parallax bg: image active floutée derrière
  function updateBg(){
    if (!bg || reducedMotion) return;
    var c = cards[active];
    if (!c) return;
    var img = c.querySelector('.cov-img');
    var src = img && img.getAttribute('src');
    if (!src) return;
    if (bg._lastSrc === src) return;
    bg._lastSrc = src;
    bg.style.backgroundImage = 'url("'+src+'")';
    bg.classList.add('is-ready');
  }

  // Build dots
  dots.innerHTML = cards.map(function(_,i){ return '<button class="cov-dot" data-i="'+i+'" aria-label="Slide '+(i+1)+'"></button>'; }).join('');

  function layout(){
    var cardW = cards[0] ? cards[0].offsetWidth : 300;
    var n = cards.length;
    cards.forEach(function(c,i){
      // Distance cyclique signée: shortest path dans l'anneau (loop infini)
      var d = i - active;
      if (d > n/2) d -= n;
      else if (d < -n/2) d += n;
      var abs = Math.abs(d);
      var sign = d<0 ? -1 : 1;
      var translatePx, rotate, scale, z, opacity;
      if (d===0){
        translatePx=0; rotate=0; scale=1; z=100; opacity=1;
      } else if (abs===1){
        translatePx=sign*cardW*0.56; rotate=sign*-22; scale=.92; z=80; opacity=.95;
      } else if (abs===2){
        translatePx=sign*cardW*0.96; rotate=sign*-30; scale=.82; z=60; opacity=.75;
      } else if (abs===3){
        translatePx=sign*cardW*1.24; rotate=sign*-37; scale=.70; z=40; opacity=.40;
      } else {
        translatePx=sign*cardW*1.4; rotate=sign*-44; scale=.58; z=20; opacity=0;
      }
      c.style.transform = 'translate(-50%,-50%) translateX('+translatePx+'px) rotateY('+rotate+'deg) scale('+scale+')';
      c.style.zIndex = z;
      c.style.opacity = opacity;
      c.style.pointerEvents = abs>3 ? 'none' : 'auto';
      c.classList.toggle('is-active', d===0);
    });
    Array.from(dots.children).forEach(function(dt,i){ dt.classList.toggle('is-active', i===active); });
    updateBg();
  }

  // Re-layout on resize (card width change)
  window.addEventListener('resize', function(){
    if (root.isConnected) layout();
  });

  function goTo(i){
    // Loop infini: wrap modulo N
    var n = cards.length;
    active = ((i % n) + n) % n;
    layout();
    var cat = cards[active].dataset.cat;
    // auto scroll active dot into view si beaucoup
    var adot = dots.children[active];
    if (adot && adot.scrollIntoView) adot.scrollIntoView({block:'nearest',inline:'center',behavior:'smooth'});
  }

  prev.addEventListener('click', function(){ goTo(active-1); });
  next.addEventListener('click', function(){ goTo(active+1); });
  dots.addEventListener('click', function(e){
    var t = e.target.closest('.cov-dot'); if (!t) return;
    goTo(parseInt(t.dataset.i,10));
  });

  cards.forEach(function(c,i){
    c.addEventListener('click', function(){
      if (i === active){
        selectCatFromGrid(c.dataset.cat);
      } else {
        goTo(i);
      }
    });
  });

  // Keyboard
  root.tabIndex = 0;
  root.addEventListener('keydown', function(e){
    if (e.key==='ArrowLeft'){ goTo(active-1); e.preventDefault(); }
    else if (e.key==='ArrowRight'){ goTo(active+1); e.preventDefault(); }
    else if (e.key==='Enter'||e.key===' '){ selectCatFromGrid(cards[active].dataset.cat); e.preventDefault(); }
  });

  // Drag live touch (mobile) — card suit le doigt en temps réel
  var dragOffset = 0;         // offset px en cours de drag
  var lastMoveX = 0;          // tracking vitesse
  var lastMoveT = 0;
  var velocity = 0;           // px/ms
  var dragAxisLocked = false; // once horiz decided, preventDefault le reste
  var dragIsHoriz = false;

  function applyLayoutWithDrag(offset){
    var cardW = cards[0] ? cards[0].offsetWidth : 300;
    var n = cards.length;
    var fracShift = offset / cardW; // 1.0 = décale une position entière
    // Tilt global pendant drag: sway direction geste = effet aérien
    var dragTilt = Math.max(-6, Math.min(6, -fracShift * 6)); // deg rotateZ
    var liftY = Math.abs(fracShift) > 0.02 ? -4 : 0; // lift 4px pendant drag
    cards.forEach(function(c,i){
      var d = i - active - fracShift;
      if (d > n/2) d -= n;
      else if (d < -n/2) d += n;
      var abs = Math.abs(d);
      var sign = d<0 ? -1 : (d>0 ? 1 : 0);
      var translatePx, rotate, scale, z, opacity;
      if (abs < 0.001){
        translatePx=0; rotate=0; scale=1; z=100; opacity=1;
      } else if (abs <= 1){
        var t = abs;
        translatePx = sign * cardW * (0 + 0.56 * t);
        rotate = sign * -22 * t; // moins agressif (aérien)
        scale = 1 - 0.08 * t;    // plus doux
        z = Math.round(100 - 20*t);
        opacity = 1 - 0.05 * t;  // adjacentes +visibles
      } else if (abs <= 2){
        var t2 = abs - 1;
        translatePx = sign * cardW * (0.56 + 0.40 * t2);
        rotate = sign * (-22 + -8*t2);
        scale = 0.92 - 0.10*t2;
        z = Math.round(80 - 20*t2);
        opacity = 0.95 - 0.20*t2; // 0.95 → 0.75
      } else if (abs <= 3){
        var t3 = abs - 2;
        translatePx = sign * cardW * (0.96 + 0.28 * t3);
        rotate = sign * (-30 + -7*t3);
        scale = 0.82 - 0.12*t3;
        z = Math.round(60 - 20*t3);
        opacity = 0.75 - 0.35*t3; // 0.75 → 0.40
      } else {
        translatePx = sign * cardW * 1.4;
        rotate = sign * -44;
        scale = 0.58;
        z = 20;
        opacity = 0;
      }
      // Card active: tilt Z + lift pendant drag
      var rotZ = (abs < 0.5) ? dragTilt : 0;
      var ty = (abs < 0.5) ? liftY : 0;
      c.style.transform = 'translate(-50%,-50%) translateX('+translatePx+'px) translateY('+ty+'px) rotateY('+rotate+'deg) rotateZ('+rotZ+'deg) scale('+scale+')';
      c.style.zIndex = z;
      c.style.opacity = opacity;
      c.style.pointerEvents = abs>3 ? 'none' : 'auto';
      c.classList.toggle('is-active', Math.round(active + fracShift) % n === i);
    });
    Array.from(dots.children).forEach(function(dt,i){ dt.classList.toggle('is-active', i===active); });
  }

  function setTransitionAll(enable){
    // Spring très mou mobile = flottement aérien (pas de bounce, ease out très doux)
    var isMobile = window.innerWidth < 768;
    var dur = enable ? (isMobile ? '.85s' : '.55s') : '0s';
    var easing = enable ? (isMobile ? 'cubic-bezier(.16,.68,.24,1)' : 'var(--spring-apple,cubic-bezier(.32,.72,0,1))') : 'linear';
    cards.forEach(function(c){
      c.style.transition = 'transform '+dur+' '+easing+', opacity '+dur+' '+easing+', box-shadow .7s ease, filter .5s ease';
    });
  }

  function onTouchStart(e){
    touching = true;
    touchStartX = e.touches[0].clientX;
    touchStartY = e.touches[0].clientY;
    lastMoveX = touchStartX;
    lastMoveT = Date.now();
    velocity = 0;
    dragOffset = 0;
    dragAxisLocked = false;
    dragIsHoriz = false;
    root.classList.add('is-dragging');
    setTransitionAll(false);
  }

  function onTouchMove(e){
    if (!touching) return;
    var x = e.touches[0].clientX;
    var y = e.touches[0].clientY;
    var dx = x - touchStartX;
    var dy = y - touchStartY;
    if (!dragAxisLocked){
      if (Math.abs(dx) > 4 || Math.abs(dy) > 4){
        dragIsHoriz = Math.abs(dx) > Math.abs(dy) * 1.2;
        dragAxisLocked = true;
        if (dragIsHoriz){
          root.style.touchAction = 'none';
          // Lock page scroll quand drag horiz: position:fixed body + save scroll
          var sy = window.scrollY || window.pageYOffset || 0;
          document.body.dataset.covLockY = sy;
          document.body.style.top = '-' + sy + 'px';
          document.body.classList.add('cov-body-lock');
        }
      }
    }
    if (!dragIsHoriz) return;
    // Kill tout scroll natif sur ce geste (y compris swipe back iOS/Chrome)
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();
    var now = Date.now();
    var dt = Math.max(1, now - lastMoveT);
    velocity = (x - lastMoveX) / dt;
    lastMoveX = x;
    lastMoveT = now;
    dragOffset = -dx;
    applyLayoutWithDrag(dragOffset);
  }

  function onTouchEnd(){
    if (!touching) return;
    touching = false;
    root.classList.remove('is-dragging');
    root.style.touchAction = '';
    if (document.body.classList.contains('cov-body-lock')){
      document.body.classList.remove('cov-body-lock');
      document.body.style.top = '';
      var sy = parseInt(document.body.dataset.covLockY || '0', 10);
      window.scrollTo(0, sy);
      delete document.body.dataset.covLockY;
    }
    setTransitionAll(true);
    if (!dragIsHoriz){ dragOffset = 0; return; }
    var cardW = cards[0] ? cards[0].offsetWidth : 300;
    var projection = dragOffset - velocity * 160;
    var steps = Math.round(projection / cardW);
    steps = Math.max(-3, Math.min(3, steps));
    if (steps === 0 && Math.abs(velocity) > 0.4){
      steps = velocity < 0 ? 1 : -1;
    }
    dragOffset = 0;
    goTo(active + steps);
  }

  function onTouchCancel(){
    if (!touching) return;
    touching = false;
    root.classList.remove('is-dragging');
    root.style.touchAction = '';
    if (document.body.classList.contains('cov-body-lock')){
      document.body.classList.remove('cov-body-lock');
      document.body.style.top = '';
      var sy = parseInt(document.body.dataset.covLockY || '0', 10);
      window.scrollTo(0, sy);
      delete document.body.dataset.covLockY;
    }
    setTransitionAll(true);
    dragOffset = 0;
    layout();
  }

  // Attache sur root (stage entière) + document pour captage global pendant drag
  root.addEventListener('touchstart', onTouchStart, {passive:true});
  root.addEventListener('touchmove', onTouchMove, {passive:false});
  root.addEventListener('touchend', onTouchEnd);
  root.addEventListener('touchcancel', onTouchCancel);
  // Doigt peut sortir du stage → doc-level fallback
  document.addEventListener('touchmove', function(e){
    if (touching && dragIsHoriz) { if (e.cancelable) e.preventDefault(); }
  }, {passive:false});
  document.addEventListener('touchend', function(){ if (touching) onTouchEnd(); });
  document.addEventListener('touchcancel', function(){ if (touching) onTouchCancel(); });

  // Mouse wheel horizontal (desktop touchpad)
  track.addEventListener('wheel', function(e){
    if (Math.abs(e.deltaX) > Math.abs(e.deltaY) && Math.abs(e.deltaX) > 20){
      e.preventDefault();
      goTo(active + (e.deltaX>0 ? 1 : -1));
    }
  }, {passive:false});

  layout();

  // Entrance animation: stagger cascade sauf reduced-motion ou low-end
  if (!reducedMotion && !document.documentElement.classList.contains('low-end')){
    cards.forEach(function(c,i){
      // distance signée cyclique au centre
      var n = cards.length;
      var d = i - active;
      if (d > n/2) d -= n;
      else if (d < -n/2) d += n;
      var delay = Math.abs(d) * 140; // 140ms par rang (plus posé)
      c.style.animationDelay = delay + 'ms';
    });
    root.classList.add('cov-enter');
    // Nettoyage: retire classe après anim pour pas gêner futures transitions
    setTimeout(function(){
      root.classList.remove('cov-enter');
      cards.forEach(function(c){ c.style.animationDelay = ''; });
    }, 2800);
  }
}

function selectCatFromGrid(cat) {
  activeCategory = cat;
  if (cat !== 'Tout') { _markCatSeen(cat); }
  renderMobCatbar();
  renderToolbar();
  renderCatGrid();
  renderVideos();
  _updateAluneNew();
  if (cat === 'Tout') {
    _scrollToEl(document.getElementById('catGridSection'), -4);
  } else {
    _scrollToEl(document.getElementById('content'));
  }
}

function _hideLoader() {
  var loader = document.getElementById('lfiagLoader');
  if (loader && !loader._hiding) {
    loader._hiding = true;
    loader.classList.add('lfiag-hide');
    setTimeout(function() { if (loader && loader.parentNode) loader.parentNode.removeChild(loader); }, 750);
  }
}
function _scrollToEl(el, extraOffset) {
  if (!el) return;
  extraOffset = extraOffset || 0;
  requestAnimationFrame(function() {
    requestAnimationFrame(function() {
      // Mesurer la hauteur cumulée de TOUS les éléments sticky/fixed en haut de page
      var stickyH = 0;
      var selectors = ['header', '#mobTopbar', '.mob-topbar', '#mobCatbar'];
      selectors.forEach(function(sel) {
        var bar = document.querySelector(sel);
        if (!bar) return;
        var style = window.getComputedStyle(bar);
        var pos = style.position;
        if ((pos === 'sticky' || pos === 'fixed') && bar.offsetParent !== null) {
          var rect = bar.getBoundingClientRect();
          // Ne compter que si l'élément est visible en haut de l'écran
          if (rect.bottom > 0 && rect.top <= 0) {
            stickyH = Math.max(stickyH, rect.bottom);
          } else if (rect.top >= 0 && rect.top < 120) {
            stickyH = Math.max(stickyH, rect.bottom);
          }
        }
      });
      stickyH = stickyH || 0;
      var top = el.getBoundingClientRect().top + window.scrollY - stickyH - 12 + extraOffset;
      window.scrollTo({ top: Math.max(0, top), behavior: 'smooth' });
    });
  });
}

function renderAll() {
  if (window._loaderSafetyTimer) { clearTimeout(window._loaderSafetyTimer); window._loaderSafetyTimer = null; }
  showScreen('app');
  // Injecter PDFs statiques (Lara Fabian - Livres)
  var _PDFS = [{"id": "1ssmXBK3mXtsiPWSrawKqjb2YZZcMA1Dj", "name": "Lara Fabian - Je passe à table.pdf", "mimeType": "application/pdf", "size": "7640667", "createdTime": "2026-04-07T18:45:58.602Z", "modifiedTime": "2026-04-07T18:45:58.602Z", "thumbnailLink": "https://drive.google.com/thumbnail?id=1ssmXBK3mXtsiPWSrawKqjb2YZZcMA1Dj&sz=w640", "webViewLink": "https://drive.google.com/file/d/1ssmXBK3mXtsiPWSrawKqjb2YZZcMA1Dj/view", "_category": "Lara Fabian - Livres", "_cat": "Lara Fabian - Livres"}, {"id": "1fRG0WiZPqFhwZdd3MqrFuupeesU3-W58", "name": "Lara Fabian - Derrière la voix.pdf", "mimeType": "application/pdf", "size": "7975554", "createdTime": "2025-04-24T13:22:00.298Z", "modifiedTime": "2025-04-24T13:22:12.598Z", "thumbnailLink": "https://drive.google.com/thumbnail?id=1fRG0WiZPqFhwZdd3MqrFuupeesU3-W58&sz=w640", "webViewLink": "https://drive.google.com/file/d/1fRG0WiZPqFhwZdd3MqrFuupeesU3-W58/view", "_category": "Lara Fabian - Livres", "_cat": "Lara Fabian - Livres"}];
  _PDFS.forEach(function(p){ if (!allVideos.some(function(v){return v.id===p.id;})) allVideos.push(p); });
  var loader = document.getElementById('lfiagLoader');
  if (loader && !loader._hiding) {
    loader._hiding = true;
    var remaining = Math.max(0, 4500 - (window._loaderStart ? Date.now() - window._loaderStart : 9999));
    setTimeout(function() {
      loader.classList.add('lfiag-hide');
      setTimeout(function() { if (loader && loader.parentNode) loader.parentNode.removeChild(loader); }, 750);
    }, remaining);
  }
  window._sharedStats = getSharedStats();
  if (isMobile()) { renderMobCatbar(); } else { renderDeskCatBar(); }
  renderCatDrawer();
  renderCatGrid();
  renderVideos();
  updateHeroWidgets();
  updateAluneSection();
  try{document.dispatchEvent(new CustomEvent('lfiag:ready'));}catch(e){}
  setTimeout(_updateAluneNew, 100);
}

function updateAluneSection() {
  // Afficher la section seulement si les catégories existent dans les données
  var sec = document.getElementById('aluneSection');
  if (!sec) return;
  var cats = allVideos.map(function(v){ return v._cat; });
  var hasVoice  = cats.indexOf('The Voice 2026') >= 0;
  var hasEffet  = cats.some(function(c){ return c && c.toLowerCase().indexOf('effet lara') >= 0; });
  sec.style.display = (hasVoice || hasEffet) ? '' : 'none';
}

function setAluneCategory(cat) {
  _markCatSeen(cat);
  selectCatFromGrid(cat);
}

function renderVideosAlune(cat) {
  var el = document.getElementById('content');
  var filtered = allVideos.filter(function(v) { return v._cat === cat; });
  var sorted = applySortToVideos(filtered);
  var catName = (cat === 'L EFFET LARA - 2026' || cat === "L'Effet Lara - 2026") ? "L'Effet Lara" : cat;
  if (!sorted.length) {
    el.innerHTML = '<div class="empty-state"><h3>Aucune vidéo trouvée</h3></div>';
    return;
  }
  el.innerHTML =
    '<div class="section-header">'
    + '<span class="section-title">' + escHtml(catName) + '</span>'
    + '<span class="section-count">' + sorted.length + ' vidéo' + (sorted.length > 1 ? 's' : '') + '</span>'
    + '<div class="section-divider"></div>'
    + '</div>'
    + '<div class="video-grid">' + sorted.map(function(v){ return videoCard(v); }).join('') + '</div>';
}

function updateHeroWidgets() {
  // Compteur animé
  var counter = document.getElementById('heroCounter');
  var numEl   = document.getElementById('heroCounterNum');
  if (counter && numEl && allVideos.length > 0) {
    counter.style.display = 'inline-flex';
    animateCounter(numEl, 0, allVideos.length, 800);
  }
  // Bouton Continuer à regarder
  var btn = document.getElementById('heroContinueBtn');
  if (btn) {
    var lastId = getLastWatchedId();
    btn.style.display = lastId ? 'inline-flex' : 'none';
  }
}

function animateCounter(el, from, to, duration) {
  var start = null;
  function step(ts) {
    if (!start) start = ts;
    var progress = Math.min((ts - start) / duration, 1);
    var ease = 1 - Math.pow(1 - progress, 3); // ease-out cubic
    el.textContent = Math.floor(from + (to - from) * ease);
    if (progress < 1) requestAnimationFrame(step);
    else el.textContent = to;
  }
  requestAnimationFrame(step);
}

function getLastWatchedId() {
  try {
    var h = JSON.parse(localStorage.getItem('lfiag_history') || '{}');
    var entries = Object.entries(h);
    if (!entries.length) return null;
    entries.sort(function(a, b) { return (b[1].ts||0) - (a[1].ts||0); });
    return entries[0][0]; // on fait confiance à l'historique sans vérifier allVideos
  } catch(e) { return null; }
}

function heroContinueWatching() {
  var id = getLastWatchedId();
  if (id) openVideo(id);
}

function getFiltered() {
  let v = allVideos;
  if (searchQuery) { const q = searchQuery.toLowerCase(); v = v.filter(x => x.name.toLowerCase().includes(q)); }
  if (activeCategory !== 'Tout') v = v.filter(x => x._cat === activeCategory);
  return v;
}

function renderToolbar() {
  if (isMobile()) return;
  var tb = document.getElementById('toolbar');
  if (!tb) return;
  var activeLabel = activeCategory==='__new__'?'Derniers ajouts':activeCategory==='Tout'?'Tout':activeCategory;
  var sortLabels = {date_desc:'&#8595;&nbsp;R&#xe9;cent',date_asc:'&#8593;&nbsp;Ancien',name_asc:'A&#8211;Z'};
  var sortPills = ['date_desc','date_asc','name_asc'].map(function(s){
    return '<div class="cat-pill sort-pill'+(sortOrder===s?' active':'')+'" data-sort="'+escAttr(s)+'" onclick="setSort(this.dataset.sort)">'+sortLabels[s]+'</div>';
  }).join('');
  tb.innerHTML =
    '<div style="width:100%;display:flex;align-items:center;gap:.5rem;">'
    +'<button class="desk-cat-btn" onclick="toggleDeskDrawer()">'
    +'<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><line x1="3" y1="6" x2="3.01" y2="6"/><line x1="3" y1="12" x2="3.01" y2="12"/><line x1="3" y1="18" x2="3.01" y2="18"/></svg>'
    +'Cat&#xe9;gories&ensp;<span style="color:var(--gold);font-weight:700;">'+escHtml(activeLabel)+'</span>'
    +'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="opacity:.5"><polyline points="6 9 12 15 18 9"/></svg>'
    +'</button>'
    +'<div style="margin-left:auto;display:flex;gap:.35rem;">'+sortPills+'</div>'
    +'</div>';
  renderDeskDrawerList();
}

function renderDeskCatBar() {
  // Bouton label catégorie active
  var activeLabel = activeCategory==='__new__' ? 'Derniers ajouts'
    : activeCategory==='Tout' ? 'Tout' : activeCategory;
  var el = document.getElementById('deskCatActive');
  if (el) el.textContent = activeLabel;
  var el2 = document.getElementById('headerCatActive');
  if (el2) el2.textContent = activeLabel;

  // Pills de tri
  var sortLabels = {date_desc:'&#8595; R&#xe9;cent', date_asc:'&#8593; Ancien', name_asc:'A&#8211;Z'};
  var sg = document.getElementById('deskSortGroup');
  if (sg) sg.innerHTML = ['date_desc','date_asc','name_asc'].map(function(s){
    return '<div class="cat-pill sort-pill'+(sortOrder===s?' active':'')+'" data-sort="'+s+'" onclick="setSort(this.dataset.sort)">'+sortLabels[s]+'</div>';
  }).join('');

  // Mettre à jour la liste du dropdown
  renderDeskDrawerList();
}

function renderDeskDrawerList(query) {
  var list = document.getElementById('deskDrawerList');
  if (!list) return;
  query = (query === undefined ? (document.getElementById('deskDrawerSearch')||{}).value||'' : query).toLowerCase().trim();

  var allCats = [
    {id:'__new__', label:'✦ Derniers ajouts', count:Math.min(allVideos.length,20), special:true},
    {id:'Tout',    label:'Tout',                   count:allVideos.length, special:true}
  ].concat([...new Set(allVideos.map(function(v){return v._cat;}))].sort()
    .map(function(c){return {id:c,label:c,count:allVideos.filter(function(v){return v._cat===c;}).length};}));

  var filtered = query ? allCats.filter(function(c){return c.label.toLowerCase().includes(query);}) : allCats;

  if (!filtered.length) {
    list.innerHTML = '<div class="desk-drawer-empty">Aucune catégorie trouvée</div>';
    return;
  }

  var html = '', prevSpecial = null;
  filtered.forEach(function(cat, i) {
    // Séparateur entre items spéciaux et normaux
    if (prevSpecial === true && !cat.special && !query) html += '<div class="desk-drawer-sep"></div>';
    prevSpecial = !!cat.special;
    var act = cat.id === activeCategory ? 'active' : '';
    html += '<div class="desk-drawer-item '+act+'" data-cat="'+escAttr(cat.id)+'" onclick="selectDeskCat(this.dataset.cat)">'
      +'<span class="desk-drawer-dot"></span>'
      +'<span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+escHtml(cat.label)+'</span>'
      +'<span class="desk-drawer-count">'+cat.count+'</span>'
      +'</div>';
  });
  list.innerHTML = html;
}

function toggleDeskDrawer() {
  var drawer = document.getElementById('deskDrawer');
  if (drawer.classList.contains('open')) closeDeskDrawer();
  else openDeskDrawer();
}

function _positionDeskDrawer() {
  // Sur desktop, le bouton est dans le header (headerCatBtn)
  var headerBtn = document.getElementById('headerCatBtn');
  var btn = (headerBtn && headerBtn.offsetParent !== null) ? headerBtn : document.getElementById('deskCatBtn');
  var drawer = document.getElementById('deskDrawer');
  if (!btn || !drawer) return;
  var rect = btn.getBoundingClientRect();
  var dw   = 300;
  var top  = rect.bottom + 5;
  var left = rect.left;
  if (left + dw > window.innerWidth - 12) left = Math.max(8, window.innerWidth - dw - 12);
  drawer.style.top  = top  + 'px';
  drawer.style.left = left + 'px';
}

function openDeskDrawer() {
  var btn     = document.getElementById('deskCatBtn');
  var drawer  = document.getElementById('deskDrawer');
  var overlay = document.getElementById('deskDrawerOverlay');
  if (!btn || !drawer) return;

  renderDeskDrawerList('');
  _positionDeskDrawer();
  drawer.classList.add('open');
  btn.classList.add('open');
  var hBtn = document.getElementById('headerCatBtn'); if (hBtn) hBtn.classList.add('open');
  if (overlay) overlay.classList.add('open');

  // Suivi au scroll — repositionner en temps réel
  if (!window._deskScrollHandler) {
    var _deskScrollTick = false;
    window._deskScrollHandler = function() {
      if (!_deskScrollTick && document.getElementById('deskDrawer').classList.contains('open')) {
        _deskScrollTick = true;
        requestAnimationFrame(function() {
          _positionDeskDrawer();
          _deskScrollTick = false;
        });
      }
    };
    window.addEventListener('scroll', window._deskScrollHandler, { passive: true });
  }

  // Focus sur la recherche
  setTimeout(function() {
    var inp = document.getElementById('deskDrawerSearch');
    if (inp) inp.focus();
    var actEl = document.querySelector('#deskDrawerList .desk-drawer-item.active');
    if (actEl) actEl.scrollIntoView({block:'nearest'});
  }, 60);
}

function closeDeskDrawer() {
  var drawer  = document.getElementById('deskDrawer');
  var overlay = document.getElementById('deskDrawerOverlay');
  var btn     = document.getElementById('deskCatBtn');
  var inp     = document.getElementById('deskDrawerSearch');
  if (drawer)  drawer.classList.remove('open');
  if (overlay) overlay.classList.remove('open');
  if (btn)     btn.classList.remove('open');
  var hBtn2 = document.getElementById('headerCatBtn'); if (hBtn2) hBtn2.classList.remove('open');
  if (inp)     inp.value = '';
}

function selectDeskCat(c) {
  activeCategory = c;
  closeDeskDrawer();
  renderDeskCatBar();
  renderVideos();
  window.scrollTo({top:0, behavior:'smooth'});
}

function setCategory(c) { activeCategory = c; if(isMobile()){renderMobCatbar();}else{renderDeskCatBar();} renderVideos(); }

function videoCard(v, isNew) {
  isNew=!!isNew;
  var _h={}; try{_h=JSON.parse(localStorage.getItem('lfiag_history')||'{}')}catch(e){}
  var _lk={}; try{_lk=JSON.parse(localStorage.getItem('lfiag_likes')||'{}')}catch(e){}
  var _vw={}; try{_vw=JSON.parse(localStorage.getItem('lfiag_views')||'{}')}catch(e){}
  var seen=!!_h[v.id];
  var progress=(_h[v.id]&&_h[v.id].progress)||0;
  var myLike=_lk[v.id]||0;
  var vc_count=_vw[v.id]||0;
  var likeCount=myLike===1?1:0;
  var _cleanN = v.name.replace(/\.[^.]+$/,'');
  var _words  = _cleanN.split(/[\s\-_]+/).filter(function(w){return w.length>0;});
  var _init   = (_words.length>=2 ? _words[0][0]+_words[1][0] : _cleanN.substring(0,2)).toUpperCase();
  var _hue    = _cleanN.split('').reduce(function(a,c){return a+c.charCodeAt(0);},0)%360;
  var _bg     = 'hsl('+_hue+',35%,22%)';
  var _fg     = 'hsl('+_hue+',60%,70%)';
  var _fbk    = '<div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;background:'+_bg+';">'
    +'<span style="font-family:var(--font-display);font-size:2rem;font-weight:700;color:'+_fg+';letter-spacing:-.02em;">'+_init+'</span></div>';
  var _thumbUrl = v.thumbnailLink ? v.thumbnailLink.replace('=s220', isMobile()?'=s320':'=s560') : null;
  var thumb = _fbk + (_thumbUrl
    ? '<img src="'+_thumbUrl+'" alt="'+escHtml(v.name)+'" loading="lazy" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;" onerror="this.style.display=\'none\'">'
    : '');
  const dur = v.videoMediaMetadata && v.videoMediaMetadata.durationMillis
    ? formatDuration(parseInt(v.videoMediaMetadata.durationMillis)) : '';
  const date = v.modifiedTime
    ? new Date(v.modifiedTime).toLocaleDateString('fr-FR',{day:'numeric',month:'short',year:'numeric'}) : '';
  const newBadge = isNew ? '<div class="new-badge">Nouveau</div>' : '';
  const vuBadge  = seen  ? '<div class="seen-badge">&#10003; Vu</div>' : '';
  const ncBadge  = (currentUser&&currentUser.role==='admin'&&v._cat==='Autres') ? '<div class="new-badge" style="background:#ef4444;left:auto;right:.5rem;">Non classé</div>' : '';
  const durBadge = dur ? '<div class="duration-badge">' + dur + '</div>' : '';
  const progressBar = seen
    ? '<div class="progress-bar"><div class="progress-bar-fill" style="width:100%"></div></div>'
    : '';
  if (v.mimeType === 'application/pdf') {
    return '<div class="video-card" style="cursor:pointer" onclick="openVideo(' + JSON.stringify(v.id) + ')">' +
      '<div class="vc-thumb" style="aspect-ratio:3/4;background:#1a1a2e;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:.5rem;">' +
      (v.thumbnailLink ? '<img src="' + v.thumbnailLink + '" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:.25;" loading="lazy">' : '') +
      '<svg width="32" height="32" viewBox="0 0 24 24" fill="#c49b64"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6zm-1 1.5L18.5 9H13V3.5z"/></svg>' +
      '<span style="color:#c49b64;font-size:.65rem;font-weight:700;text-transform:uppercase;letter-spacing:.1em;">PDF</span>' +
      '</div>' +
      '<div class="vc-info"><div class="vc-title">' + escHtml(v.name.replace(/\.pdf$/i,'')) + '</div>' +
      '<div class="vc-meta" style="color:#c49b64;">📖 Lire</div></div></div>';
  }
  return '<div class="video-card" tabindex="0" onclick="openVideo(\'' + v.id + '\')">'
    + '<div class="thumb-wrap">' + thumb
    + '<div class="play-overlay"><div class="play-btn"><svg width="18" height="18" viewBox="0 0 24 24" fill="white"><polygon points="5 3 19 12 5 21 5 3"/></svg></div></div>'
    + newBadge + vuBadge + ncBadge + durBadge + progressBar + '</div>'
    + '<div class="card-body">'
    + '<div class="card-category">' + escHtml(v._cat) + '</div>'
    + '<div class="card-title">' + escHtml(v.name.replace(/\.[^.]+$/, '')) + '</div>'
    + '<div class="card-meta">' + (date?'<span>'+date+'</span>':'')
    + (vc_count>0?'<span style="opacity:.6;">\xb7 '+vc_count+' vue'+(vc_count>1?'s':'')+'</span>':'')
    + '</div>'
    + '</div></div>';
}

function setSort(s) {
  sortOrder=s;
  if(isMobile()){renderMobCatbar();}else{renderDeskCatBar();}
  renderVideos();
}

function applySortToVideos(arr) {
  return arr.slice().sort(function(a,b){
    if(sortOrder==='date_desc') return new Date(b.createdTime||0)-new Date(a.createdTime||0);
    if(sortOrder==='date_asc')  return new Date(a.createdTime||0)-new Date(b.createdTime||0);
    return (a.name||'').localeCompare(b.name||'','fr');
  });
}


function getRecentVideos(n) {
  return allVideos.slice().sort(function(a, b) {
    var ta = new Date(a.createdTime || a.modifiedTime || 0);
    var tb = new Date(b.createdTime || b.modifiedTime || 0);
    return tb - ta;
  }).slice(0, n || 20);
}

/* Streaming-pro home: render horizontal rows (one per category + recent) */
function renderStreamingRows(el){
  var recent = getRecentVideos(10);
  var cats = [...new Set(allVideos.map(function(v){return v._cat;}))].sort();
  var html = '<div class="sp-rows">';

  // Row 1: Derniers ajouts
  if (recent.length){
    html += spRow('✦ Derniers ajouts', '__new__', recent, true);
  }

  // Row 2+: Continue watching (si history)
  try{
    var h = JSON.parse(localStorage.getItem('lfiag_history')||'{}');
    var watched = Object.keys(h).map(function(id){
      return allVideos.find(function(v){return v.id===id;});
    }).filter(Boolean).slice(0,15);
    if (watched.length){
      html += spRow('Continuer à regarder', null, watched, false);
    }
  }catch(_){}

  // Rows per category
  cats.forEach(function(cat){
    var list = allVideos.filter(function(v){return v._cat===cat;});
    if (!list.length) return;
    html += spRow(cat, cat, list, false);
  });

  html += '</div>';
  el.innerHTML = html;

  // Init arrow scroll (desktop)
  el.querySelectorAll('.sp-row-arrow').forEach(function(btn){
    btn.addEventListener('click',function(e){
      e.stopPropagation();
      var row = btn.closest('.sp-row');
      var scroll = row.querySelector('.sp-row-scroll');
      var dir = btn.classList.contains('right') ? 1 : -1;
      scroll.scrollBy({left: dir * (scroll.clientWidth * 0.85), behavior:'smooth'});
    });
  });
}

function spRow(label, catId, videos, isNew){
  var clickAttr = catId ? ('onclick="selectCatFromGrid(\''+catId.replace(/'/g,"\\'")+'\')"') : '';
  var titleClass = isNew ? 'sp-row-title new-title' : 'sp-row-title';
  var cards = videos.map(function(v){
    var c = videoCard(v, isNew);
    // inject data-title attr for CSS ::after
    return '<div class="sp-row-card">' + c + '</div>';
  }).join('');
  return '<div class="sp-row">'
    + '<div class="sp-row-head">'
      + '<span class="'+titleClass+'" '+clickAttr+'>'+escHtml(label)
        + ' <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="9 6 15 12 9 18"/></svg>'
      + '</span>'
      + '<span class="sp-row-count">'+videos.length+'</span>'
    + '</div>'
    + '<button class="sp-row-arrow left" aria-label="Précédent"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg></button>'
    + '<button class="sp-row-arrow right" aria-label="Suivant"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="9 18 15 12 9 6"/></svg></button>'
    + '<div class="sp-row-scroll">'+cards+'</div>'
  + '</div>';
}

function renderVideos() {
  var el = document.getElementById('content');
  var newSec = document.getElementById('newSection');

  // Vue "Derniers ajouts" (__new__)
  if (activeCategory === '__new__') {
    if (newSec) newSec.style.display = 'none';
    el.style.display = '';
    var recent = getRecentVideos(4);
    el.innerHTML =
      '<div class="section-header"><span class="section-title new-title">✦ Derniers ajouts</span>' +
      '<span class="section-count">' + recent.length + ' vidéo' + (recent.length>1?'s':'') + '</span>' +
      '<div class="section-divider"></div></div>' +
      '<div class="video-grid">' + recent.map(function(v){return videoCard(v,true);}).join('') + '</div>';
    return;
  }

  // Vue "Tout" sans recherche : affiche Derniers ajouts + coverflow univers (géré par renderCatGrid)
  if (activeCategory === 'Tout' && !searchQuery) {
    el.style.display = 'none';
    el.innerHTML = '';
    if (newSec) {
      newSec.style.display = '';
      var inner = document.getElementById('newSectionInner');
      if (inner) {
        var recent4 = getRecentVideos(4);
        inner.innerHTML =
          '<div class="section-header"><span class="section-title new-title">✦ Derniers ajouts</span>' +
          '<span class="section-count">' + recent4.length + ' vidéo' + (recent4.length>1?'s':'') + '</span>' +
          '<div class="section-divider"></div></div>' +
          '<div class="video-grid">' + recent4.map(function(v){return videoCard(v,true);}).join('') + '</div>';
      }
    }
    return;
  }

  // Vue catégorie filtrée ou recherche
  if (newSec) newSec.style.display = 'none';
  el.style.display = '';
  const filtered = getFiltered();
  if (!filtered.length) {
    el.innerHTML = '<div class="empty-state"><h3>Aucune vidéo trouvée</h3><p>' +
      (searchQuery ? 'Aucun résultat pour « ' + escHtml(searchQuery) + ' »' : 'Aucune vidéo disponible.') +
      '</p></div>';
    return;
  }
  var backBtn = (activeCategory !== 'Tout' && activeCategory !== '__new__' && !searchQuery)
    ? '<span class="back-to-grid" onclick="selectCatFromGrid(\'Tout\')">'
      + '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg>'
      + ' Retour aux univers</span>' : '';
  el.innerHTML =
    (backBtn ? '<div>' + backBtn + '</div>' : '') +
    '<div class="section-header"><span class="section-title">' +
    (activeCategory!=='Tout'?escHtml(activeCategory):'Résultats') +
    '</span><span class="section-count">' + filtered.length + ' vidéo' + (filtered.length>1?'s':'') + '</span>' +
    '<div class="section-divider"></div></div>' +
    '<div class="video-grid">' + applySortToVideos(filtered).map(function(v){return videoCard(v);}).join('') + '</div>';
}

function stopAllPreviews() {
  document.querySelectorAll('.alune-card--playing').forEach(function(card) {
    aluneStopPreview(card);
  });
  // Pause toutes les balises <video> de la page (sécurité)
  document.querySelectorAll('video').forEach(function(v) {
    v.pause(); v.currentTime = 0;
  });
  // Stop video card hover previews
  document.querySelectorAll('.video-card-preview.show').forEach(function(p){
    p.classList.remove('show');
    p.innerHTML = '';
  });
}

// ============================================
// DESKTOP video-card hover preview (Drive iframe)
// ============================================
(function(){
  var _isDesktop = window.matchMedia && window.matchMedia('(min-width:1024px) and (hover:hover)').matches;
  var _lowEnd = document.documentElement.classList.contains('low-end');
  if (!_isDesktop || _lowEnd) return;
  var _hoverTimer = null;
  var _activeCard = null;
  var HOVER_DELAY = 1200; // ms before preview loads

  function _getVideoId(card){
    var onclick = card.getAttribute('onclick') || '';
    var m = onclick.match(/openVideo\(['"]([^'"]+)['"]\)/);
    return m ? m[1] : null;
  }

  function _stopPreview(card){
    if (!card) return;
    var p = card.querySelector('.video-card-preview');
    if (p){ p.classList.remove('show'); setTimeout(function(){ if(!p.classList.contains('show')) p.innerHTML=''; }, 320); }
  }

  function _startPreview(card){
    var id = _getVideoId(card);
    if (!id) return;
    var thumbWrap = card.querySelector('.thumb-wrap');
    if (!thumbWrap) return;
    var p = thumbWrap.querySelector('.video-card-preview');
    if (!p){
      p = document.createElement('div');
      p.className = 'video-card-preview';
      thumbWrap.appendChild(p);
    }
    if (p.dataset.vid !== id){
      p.innerHTML = '<iframe src="https://drive.google.com/file/d/'+id+'/preview?autoplay=1&mute=1" allow="autoplay" frameborder="0"></iframe>';
      p.dataset.vid = id;
    }
    requestAnimationFrame(function(){ p.classList.add('show'); });
  }

  document.addEventListener('mouseover', function(e){
    var card = e.target.closest && e.target.closest('.video-card');
    if (!card || card === _activeCard) return;
    if (_hoverTimer) clearTimeout(_hoverTimer);
    _activeCard = card;
    _hoverTimer = setTimeout(function(){
      _startPreview(card);
      _hoverTimer = null;
    }, HOVER_DELAY);
  });

  document.addEventListener('mouseout', function(e){
    var card = e.target.closest && e.target.closest('.video-card');
    if (!card) return;
    var to = e.relatedTarget;
    if (to && card.contains(to)) return; // still inside card
    if (_hoverTimer) { clearTimeout(_hoverTimer); _hoverTimer = null; }
    _stopPreview(card);
    if (card === _activeCard) _activeCard = null;
  });

  // Scroll = cancel pending preview
  window.addEventListener('scroll', function(){
    if (_hoverTimer) { clearTimeout(_hoverTimer); _hoverTimer = null; }
  }, {passive:true});
})();

function openVideo(id) {
  stopAllPreviews(); // ← stopper son des vignettes AVANT tout
  var v = allVideos.find(function(x){ return x.id === id; });
  if (!v) return;

  var title     = v.name.replace(/\.[^.]+$/, '');
  if (v.mimeType === 'application/pdf') { window.open(v.webViewLink, '_blank', 'noopener,noreferrer'); return; }
  var driveLink = v.webViewLink || ('https://drive.google.com/file/d/' + id + '/view');
  window._currentDriveLink = driveLink;

  document.getElementById('modalTitle').textContent = title;
  document.getElementById('modalDriveLink').href = driveLink;
  var mobLink = document.getElementById('modalDriveLinkMob');
  if (mobLink) mobLink.href = driveLink;

  var dur = v.dur ? formatDuration(parseInt(v.dur)) : null;
  var date = v.modifiedTime
    ? new Date(v.modifiedTime).toLocaleDateString('fr-FR',{day:'numeric',month:'long',year:'numeric'}) : null;
  var meta = '<span class="pill">' + escHtml(v._cat) + '</span>';
  if (dur)  meta += '<span>&#9201; ' + dur + '</span>';
  if (date) meta += '<span>&#128197; ' + date + '</span>';
  document.getElementById('modalMeta').innerHTML = meta;

  // TV : ouvrir directement le lien Drive dans le navigateur
  if (document.documentElement.classList.contains('is-tv')) {
    window.open(driveLink, '_blank', 'noopener,noreferrer');
    // Enregistrer quand même dans l'historique et les vues
    try {
      var vwt=JSON.parse(localStorage.getItem('lfiag_views')||'{}');
      vwt[id]=(vwt[id]||0)+1;
      localStorage.setItem('lfiag_views',JSON.stringify(vwt));
      var _hht=JSON.parse(localStorage.getItem('lfiag_history')||'{}');
      _hht[id]={ts:Date.now()};
      localStorage.setItem('lfiag_history',JSON.stringify(_hht));
    } catch(e) {}
    setTimeout(function(){ updateHeroWidgets(); }, 100);
    return;
  }

  var _mp = document.getElementById('modalPlayer');
  _mp.innerHTML = '';
  _mp.style.position = 'relative';
  buildIframePlayer(_mp, id);

  var _m=document.getElementById('modal');
  _m._currentVideoId=id;
  try {
    var vw=JSON.parse(localStorage.getItem('lfiag_views')||'{}');
    vw[id]=(vw[id]||0)+1;
    localStorage.setItem('lfiag_views',JSON.stringify(vw));
    if(!window._sharedStats) window._sharedStats={};
    if(!window._sharedStats[id]) window._sharedStats[id]={views:0,likes:0};
    window._sharedStats[id].views=vw[id];
  } catch(e) {}
  _m.classList.add('open');
  document.body.style.overflow='hidden';
  // Enregistrer immédiatement dans l'historique à l'ouverture
  try {
    var _hh = JSON.parse(localStorage.getItem('lfiag_history')||'{}');
    _hh[id] = {ts: Date.now()};
    localStorage.setItem('lfiag_history', JSON.stringify(_hh));
  } catch(e) {}
  setTimeout(function(){ updateModalLikes(id); }, 50);
  // Rafraîchir le bouton hero
  setTimeout(function(){ updateHeroWidgets(); }, 100);
}

function buildIframePlayer(container, id) {
  var isTV = document.documentElement.classList.contains('is-tv');
  var _sp = document.createElement('div');
  _sp.id = 'playerSpinner';
  _sp.style.cssText = 'position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#000;gap:.75rem;z-index:2;';
  _sp.innerHTML = '<div style="width:36px;height:36px;border:3px solid rgba(196,155,100,.2);border-top-color:#c49b64;border-radius:50%;animation:spin .7s linear infinite;"></div><p style="color:#8a7060;font-size:.78rem;">Chargement…</p>';
  var _if = document.createElement('iframe');
  _if.id = 'videoIframe';
  // Sur TV : utiliser /preview?rm=minimal=false pour forcer les contrôles
  // Le paramètre rm=embedded force le player complet avec contrôles toujours visibles
  _if.src = 'https://drive.google.com/file/d/' + id + '/preview' + (isTV ? '?rm=embedded' : '');
  _if.setAttribute('allow','autoplay; encrypted-media; fullscreen; picture-in-picture');
  _if.setAttribute('allowfullscreen','');
  _if.setAttribute('webkit-playsinline','');
  _if.setAttribute('playsinline','');
  _if.allowFullscreen = true;
  _if.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;border:none;opacity:0;transition:opacity .3s;';
  _if.addEventListener('load', function(){
    var s=document.getElementById('playerSpinner');if(s)s.style.display='none';
    _if.style.opacity='1';
    // Sur TV : focus le iframe pour que D-pad fonctionne à l'intérieur
    if(isTV) { setTimeout(function(){ _if.focus(); }, 300); }
  });
  container.appendChild(_sp);
  container.appendChild(_if);

  // iOS : bouton fullscreen (orientationchange + manuel)
  var isIOS = /iPhone|iPad|iPod/.test(navigator.userAgent) && !window.MSStream;
  if (isIOS) {
    var iosBtn = document.createElement('button');
    iosBtn.className = 'ios-fs-btn';
    iosBtn.innerHTML = '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"/></svg> Plein écran';
    iosBtn.addEventListener('click', function() { if(_iosFakeFS) _iosExitFakeFS(); else _iosEnterFakeFS(); });
    container.appendChild(iosBtn);
  }

  // Sur TV : bouton plein écran accessible au D-pad
  if(isTV) {
    var fsBtn = document.createElement('button');
    fsBtn.id = 'tvFullscreenBtn';
    fsBtn.textContent = '⛶ Plein écran';
    fsBtn.style.cssText = 'position:absolute;bottom:12px;right:12px;z-index:10;background:rgba(0,0,0,.7);color:#fff;border:1px solid rgba(255,255,255,.3);border-radius:8px;padding:.45rem .9rem;font-size:.82rem;cursor:pointer;';
    fsBtn.addEventListener('click', function(){
      var el = document.getElementById('modalPlayer') || document.getElementById('modal');
      if(el && el.requestFullscreen) el.requestFullscreen();
      else if(el && el.webkitRequestFullscreen) el.webkitRequestFullscreen();
    });
    container.appendChild(fsBtn);
  }
}

function iframeLoaded() {
  var s=document.getElementById('playerSpinner'); if(s)s.style.display='none';
  var f=document.getElementById('videoIframe');   if(f)f.style.opacity='1';
}

function closeModal() {
  var modal=document.getElementById('modal'), vid=modal._currentVideoId;
  if(vid){ try{ var h=JSON.parse(localStorage.getItem('lfiag_history')||'{}'); h[vid]={ts:Date.now()}; localStorage.setItem('lfiag_history',JSON.stringify(h)); }catch(e){} modal._currentVideoId=null; }
  if(typeof _iosFakeFS !== 'undefined' && _iosFakeFS) _iosExitFakeFS();
  modal.classList.remove('open');
  document.getElementById('modalPlayer').innerHTML='';
  document.body.style.overflow='';
  stopAllPreviews(); // sécurité : au cas où une preview a démarré pendant le modal
  updateHeroWidgets();
}





document.getElementById('modal').addEventListener('click', function(e){ if(e.target===this) closeModal(); });
document.addEventListener('keydown', e=>{ if(e.key==='Escape') closeModal(); });

// ============================================
// SETTINGS
// ============================================
function renderRules() {
  var el=document.getElementById('ruleList');if(!el)return;
  el.innerHTML = settings.rules.map((r,i)=>`<div class="tag-rule"><span class="keyword">${escHtml(r.keyword)}</span><span class="arrow">→</span><span class="cat">${escHtml(r.cat)}</span><button class="tag-rule-delete" onclick="deleteRule(${i})">×</button></div>`).join('')||'<span style="color:var(--muted);font-size:.82rem;">Aucune règle</span>';
}
function addRule() { const kw=document.getElementById('ruleKeyword').value.trim(),cat=document.getElementById('ruleCat').value.trim(); if(!kw||!cat){toast('⚠ Remplissez les deux champs.');return;} settings.rules.push({keyword:kw,cat}); document.getElementById('ruleKeyword').value=''; document.getElementById('ruleCat').value=''; renderRules(); }
function deleteRule(i) { settings.rules.splice(i,1); renderRules(); }
function saveSettings() { localStorage.setItem('lfiag_settings_v2',JSON.stringify(settings)); allVideos.forEach(v=>{v._cat=categorize(v);}); renderAll(); document.getElementById('settingsPanel').classList.remove('open'); toast('✓ Paramètres enregistrés'); }

// ============================================
// HELPERS
// ============================================
function escHtml(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function escAttr(s) { return String(s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }
function getSharedStats() {
  var views = {}; var likes = {};
  try { views = JSON.parse(localStorage.getItem('lfiag_views')||'{}'); } catch(e) {}
  try { likes = JSON.parse(localStorage.getItem('lfiag_likes')||'{}'); } catch(e) {}
  var stats = {};
  Object.keys(views).forEach(function(id){ stats[id]={views:views[id]||0,likes:0}; });
  Object.keys(likes).forEach(function(id){
    if(!stats[id]) stats[id]={views:0,likes:0};
    stats[id].likes = likes[id]===1 ? 1 : 0;
  });
  return stats;
}
function getLikes() {
  try { return JSON.parse(localStorage.getItem('lfiag_likes')||'{}'); } catch(e) { return {}; }
}
function saveLikes(l) {
  try { localStorage.setItem('lfiag_likes', JSON.stringify(l)); } catch(e) {}
}
function getViewsShared() {
  try { return JSON.parse(localStorage.getItem('lfiag_views')||'{}'); } catch(e) { return {}; }
}
function toggleLike(id, val) {
  if (!id) return;
  var l=getLikes(), prev=l[id]||0;
  l[id]=(prev===val)?0:val;
  saveLikes(l);
  if(window._sharedStats){
    if(!window._sharedStats[id]) window._sharedStats[id]={views:0,likes:0};
    window._sharedStats[id].likes=l[id]===1?1:0;
  }
  // Ne pas re-render toute la grille pour un like — juste mettre à jour le modal
  updateModalLikes(id);
}
function updateModalLikes(id) {
  var l=getLikes(), vw=getViewsShared();
  var ml=l[id]||0, views=vw[id]||0;
  var lb=document.getElementById('modalLikeBtn');
  var db=document.getElementById('modalDislikeBtn');
  var lc=document.getElementById('modalLikeCount');
  var mv=document.getElementById('modalViews');
  if(lb) lb.className='modal-like-btn'+(ml===1?' active-like':'');
  if(db) db.className='modal-like-btn'+(ml===-1?' active-dislike':'');
  if(lc) lc.textContent=ml===1?1:0;
  if(mv) mv.textContent=views>0?views+' vue'+(views>1?'s':''):'';
}
function formatDuration(ms) { const s=Math.floor(ms/1000),h=Math.floor(s/3600),m=Math.floor((s%3600)/60),sec=s%60; return h>0?`${h}:${String(m).padStart(2,'0')}:${String(sec).padStart(2,'0')}`:`${m}:${String(sec).padStart(2,'0')}`; }
function toast(msg,dur=3500) { const t=document.createElement('div'); t.className='toast'; t.textContent=msg; document.getElementById('toasts').appendChild(t); setTimeout(()=>t.remove(),dur); }

function refreshWithFeedback() {
  if (window._refreshInProgress) return;
  window._refreshInProgress = true;
  if (navigator.vibrate) navigator.vibrate(10);

  var btn = document.getElementById('heroRefreshBtn');
  if (btn) btn.classList.add('loading');

  // Etape 1 : invalider le cache serveur (~5s)
  callScript('invalidate', { email: currentUser.email })
    .catch(function(){})
    .finally(function() {
      // Etape 2 : lancer la reindexation Drive cote serveur (feu et oubli, ~32s)
      // On n'attend PAS la reponse (timeout client a 30s)
      callScript('videos', { email: currentUser.email }).catch(function(){});

      // Etape 3 : informer l'utilisateur et debloquer l'UI
      if (btn) btn.classList.remove('loading');
      window._refreshInProgress = false;
      toast('⏳ Mise à jour en cours (40s)…');
      try { localStorage.removeItem('lfiag_videos_cache'); } catch(e) {}

      // Etape 4 : apres 42s le cache serveur est pret, recharger
      setTimeout(function() {
        toast('Chargement des nouvelles categories…');
        fetchAndCacheVideos(true, false)
          .then(function() { toast('✓ Categories mises a jour !'); })
          .catch(function() { toast('⚠ Reessayez dans quelques secondes'); });
      }, 42000);
    });
}

var _au=[];
function toggleAdminDropdown() {
  var dd = document.getElementById('adminDropdown');
  var isOpen = dd.classList.contains('open');
  dd.classList.toggle('open', !isOpen);
  if (!isOpen) refreshAdminUsers(); // toujours recharger à l'ouverture
  if (!isOpen) {
    setTimeout(function() {
      document.addEventListener('click', _closeAdminOut, true);
    }, 50);
  } else {
    document.removeEventListener('click', _closeAdminOut, true);
  }
}
function _closeAdminOut(e) {
  var dd = document.getElementById('adminDropdown');
  var btn = document.getElementById('adminHeaderBtn');
  if (!dd) return;
  // Ignorer si clic dans un overlay/modal par-dessus (z-index >= 500)
  var node = e.target;
  while (node && node !== document.body) {
    var z = parseInt((node.style && node.style.zIndex) || '0', 10);
    if (z >= 500) return;
    node = node.parentNode;
  }
  if (!dd.contains(e.target) && btn && !btn.contains(e.target)) {
    dd.classList.remove('open');
    document.removeEventListener('click', _closeAdminOut, true);
  }
}
function toggleAdminPanel() { toggleAdminDropdown(); }
function adminInvalidateCache(e) {
  var btn = (e && e.target) || event.target;
  btn.disabled = true;
  btn.textContent = '⏳ En cours…';
  callScript('invalidate', { email: currentUser.email })
    .then(function() {
      btn.disabled = false;
      btn.innerHTML = '&#8635; Cache';
      toast('✓ Cache serveur vidé — appuyez sur Actualiser pour recharger');
    })
    .catch(function(e) {
      btn.disabled = false;
      btn.innerHTML = '&#8635; Cache';
      toast('⚠ ' + e.message);
    });
}
function refreshAdminUsers() {
  var l = document.getElementById('adminUserList');
  if (l) l.innerHTML = '<p style="padding:.75rem 1rem;color:var(--text3);font-size:.8rem">Chargement…</p>';
  if (!currentUser || !currentUser.email) {
    if (l) l.innerHTML = '<p style="padding:.75rem 1rem;color:#ff453a;font-size:.8rem">Non connecté</p>';
    return;
  }
  callScript('list_users', { email: currentUser.email })
    .then(function(d) {
      _au = d.users || [];
      renderAdminUsers();
    })
    .catch(function(e) {
      if (l) l.innerHTML = '<p style="padding:.75rem 1rem;color:#ff453a;font-size:.8rem">⚠ ' + escHtml(e.message || 'Erreur réseau') + ' — <button onclick="refreshAdminUsers()" style="background:none;border:none;color:#ff453a;text-decoration:underline;cursor:pointer;font-size:.8rem">Réessayer</button></p>';
    });
}
function renderAdminUsers() {
  var l = document.getElementById('adminUserList');
  if (!l) return;
  if (!_au.length) { l.innerHTML = '<p style="padding:.75rem 1rem;color:var(--text3);font-size:.8rem">Aucun utilisateur.</p>'; return; }
  l.innerHTML = _au.map(function(u, i) {
    var on = u.active !== false && u.active !== 'FALSE';
    return '<div class="admin-user-row">'
      + '<div class="u-info"><div class="u-email">' + escHtml(u.email) + '</div>'
      + '<div class="u-name">' + escHtml(u.name || '—') + '</div></div>'
      + '<span class="u-active ' + (on?'on':'off') + '">' + (on?'Actif':'Inactif') + '</span>'
      + '<button class="admin-promote-btn" data-role="'+(u.role||'')+'" onclick="adminToggleRole('+i+')" title="'+(u.role==='admin'?'Retirer le rôle admin':'Promouvoir en admin')+'">'+(u.role==='admin'?'★ Admin':'☆ Admin')+'</button>'
      + '<button class="admin-del-btn" onclick="adminDeleteUser(' + i + ')">Supprimer</button>'
      + '</div>';
  }).join('');
}
function adminAddUser() {
  var e = (document.getElementById('newUserEmail').value || '').trim();
  var n = (document.getElementById('newUserName').value || '').trim();
  if (!e) { toast('⚠ Email requis'); return; }
  var btn = document.getElementById('adminAddBtn');
  if (btn) { btn.textContent = '…'; btn.disabled = true; }
  callScript('add_user', {email: currentUser.email, target_email: e, name: n})
    .then(function() {
      document.getElementById('newUserEmail').value = '';
      document.getElementById('newUserName').value = '';
      toast('✓ ' + e + ' ajouté');
      _au.push({email: e, name: n, active: true});
      renderAdminUsers();
    })
    .catch(function(err) { toast('Erreur : ' + err.message); })
    .finally(function() { if (btn) { btn.textContent = 'Ajouter'; btn.disabled = false; } });
}
function adminToggleRole(i) {
  var u = _au[i]; if (!u) return;
  var isAdmin = u.role === 'admin';
  var newRole  = isAdmin ? 'user' : 'admin';
  var label    = isAdmin ? 'Retirer admin' : 'Nommer admin';
  var question = isAdmin
    ? 'Retirer les droits admin à ' + (u.name || u.email) + ' ?'
    : 'Nommer ' + (u.name || u.email) + ' administrateur ?';
  var ok_msg = isAdmin
    ? '✓ ' + (u.name||u.email) + ' n’est plus admin'
    : '✓ ' + (u.name||u.email) + ' est maintenant admin';
  showAdminConfirm(question, label, function() {
    _au[i].role = newRole;
    renderAdminUsers();
    callScript('set_role', {email:currentUser.email, target_email:u.email, role:newRole})
      .then(function() {
        toast(ok_msg);
        if (currentUser && currentUser.email === u.email) {
          currentUser.role = newRole;
          try { localStorage.removeItem('lfiag_access'); } catch(e) {}
          var ab = document.getElementById('adminHeaderBtn');
          if (ab) ab.style.display = newRole === 'admin' ? 'flex' : 'none';
        }
      })
      .catch(function(err) {
        _au[i].role = u.role; renderAdminUsers();
        toast('⚠ Erreur : ' + err.message);
      });
  });
}

function adminDeleteUser(i) {
  var u = _au[i]; if (!u) return;
  showAdminConfirm(
    'Supprimer l’accès de ' + u.name + ' (' + u.email + ') ?',
    function() {
      callScript('toggle_user', {email: currentUser.email, target_email: u.email, active: 'false'})
        .then(function() {
          _au.splice(i, 1);
          renderAdminUsers();
          toast('✓ Accès supprimé : ' + u.email);
        })
        .catch(function(err) { _au.splice(i, 0, u); renderAdminUsers(); toast('Erreur : ' + err.message); });
    }
  );
}

function showAdminConfirm(message, actionLabel, onConfirm) {
  if (typeof actionLabel === 'function') { onConfirm = actionLabel; actionLabel = 'Confirmer'; }
  var overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,.55);display:flex;align-items:center;justify-content:center;backdrop-filter:blur(4px);padding:1rem';
  overlay.innerHTML =
    '<div style="background:rgba(10,16,32,.95);border:1px solid rgba(255,255,255,.12);border-radius:18px;padding:1.6rem 1.5rem 1.3rem;max-width:340px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,.6)">'
    + '<p style="font-size:.9rem;font-weight:600;color:#f5f5f7;margin-bottom:.5rem">' + escHtml(actionLabel) + '</p>'
    + '<p style="font-size:.8rem;color:rgba(255,255,255,.55);margin-bottom:1.3rem;line-height:1.55">' + escHtml(message) + '</p>'
    + '<div style="display:flex;gap:.6rem;justify-content:flex-end">'
    + '<button id="confirmCancel" style="padding:.52rem 1rem;border-radius:10px;background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.1);color:#f5f5f7;font-size:.82rem;cursor:pointer">Annuler</button>'
    + '<button id="confirmOk" style="padding:.52rem 1rem;border-radius:10px;background:rgba(255,69,58,.15);border:1px solid rgba(255,69,58,.35);color:#ff453a;font-size:.82rem;font-weight:600;cursor:pointer">' + escHtml(actionLabel) + '</button>'
    + '</div></div>';
  document.body.appendChild(overlay);
  overlay.querySelector('#confirmCancel').onclick = function() { overlay.remove(); };
  overlay.querySelector('#confirmOk').onclick = function() { overlay.remove(); onConfirm(); };
  overlay.onclick = function(e) { if (e.target === overlay) overlay.remove(); };
}
function adminToggleUser(i) { adminDeleteUser(i); }
